@media (width >= 56rem) {
  .manual-shell {
    display: grid;
    grid-template-columns: minmax(12rem, 18rem) minmax(0, 1fr);
    gap: 2rem;
  }
}

@media (width >= 56rem) {
  .manual-nav {
    position: sticky;
    inset-block-start: 1rem;
    align-self: start;
    max-block-size: calc(100dvh - 2rem);
    overflow-y: auto;
  }
}

@media (forced-colors: active) {
  .manual-section:target,
  .manual-shell a:focus-visible,
  .warning {
    border-color: CanvasText;
    outline-color: Highlight;
  }
}

@media print {
  .manual-shell {
    display: block;
  }
  .manual-nav {
    position: static;
    max-block-size: none;
    overflow: visible;
  }
  .code-block {
    white-space: pre-wrap;
  }
  .manual-section {
    break-inside: avoid;
  }
}
